// AuthInterceptor creates a unary server interceptor for authentication
func AuthInterceptor(validator *TokenValidator, rateLimiter *RateLimiter, auditLog *AuditLogger) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Extract peer information
		peerAddr := "unknown"
		if p, ok := peer.FromContext(ctx); ok {
			peerAddr = p.Addr.String()
		}

		// Extract metadata
		md, ok := metadata.FromIncomingContext(ctx)
		if !ok {
			auditLog.LogAuthAttempt("unknown", peerAddr, info.FullMethod, false, "no metadata")
			return nil, status.Errorf(codes.Unauthenticated, "no metadata provided")
		}

		// Extract authorization token
		authHeaders := md.Get("authorization")
		if len(authHeaders) == 0 {
			auditLog.LogAuthAttempt("unknown", peerAddr, info.FullMethod, false, "no authorization header")
			return nil, status.Errorf(codes.Unauthenticated, "no authorization token provided")
		}

		token := authHeaders[0]
		// Strip "Bearer " prefix if present
		if strings.HasPrefix(token, "Bearer ") {
			token = strings.TrimPrefix(token, "Bearer ")
		}

		// Validate token
		claims, err := validator.ValidateToken(token)
		if err != nil {
			auditLog.LogAuthAttempt("unknown", peerAddr, info.FullMethod, false, err.Error())
			return nil, status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
		}

		// Rate limiting
		if !rateLimiter.Allow(claims.ServiceID) {
			auditLog.LogAuthAttempt(claims.ServiceID, peerAddr, info.FullMethod, false, "rate limited")
			return nil, status.Errorf(codes.ResourceExhausted, "rate limit exceeded for service %s", claims.ServiceID)
		}

		// Extract and validate request ID for tracing
		requestIDs := md.Get("x-request-id")
		requestID := "none"
		if len(requestIDs) > 0 {
			requestID = requestIDs[0]
		}

		auditLog.LogAuthAttempt(claims.ServiceID, peerAddr, info.FullMethod, true,
			fmt.Sprintf("request_id=%s namespace=%s", requestID, claims.Namespace))

		// Add claims to context
		ctx = context.WithValue(ctx, claimsKey, claims)
		ctx = context.WithValue(ctx, peerAddrKey, peerAddr)

		return handler(ctx, req)
	}
}

// StreamAuthInterceptor creates a stream server interceptor for authentication
func StreamAuthInterceptor(validator *TokenValidator, rateLimiter *RateLimiter, auditLog *AuditLogger) grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		ctx := ss.Context()

		peerAddr := "unknown"
		if p, ok := peer.FromContext(ctx); ok {
			peerAddr = p.Addr.String()
		}

		md, ok := metadata.FromIncomingContext(ctx)
		if !ok {
			auditLog.LogAuthAttempt("unknown", peerAddr, info.FullMethod, false, "no metadata (stream)")
			return status.Errorf(codes.Unauthenticated, "no metadata provided")
		}

		authHeaders := md.Get("authorization")
		if len(authHeaders) == 0 {
			auditLog.LogAuthAttempt("unknown", peerAddr, info.FullMethod, false, "no authorization header (stream)")
			return status.Errorf(codes.Unauthenticated, "no authorization token provided")
		}

		token := authHeaders[0]
		if strings.HasPrefix(token, "Bearer ") {
			token = strings.TrimPrefix(token, "Bearer ")
		}

		claims, err := validator.ValidateToken(token)
		if err != nil {
			auditLog.LogAuthAttempt("unknown", peerAddr, info.FullMethod, false, err.Error())
			return status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
		}

		if !rateLimiter.Allow(claims.ServiceID) {
			auditLog.LogAuthAttempt(claims.ServiceID, peerAddr, info.FullMethod, false, "rate limited (stream)")
			return status.Errorf(codes.ResourceExhausted, "rate limit exceeded")
		}

		auditLog.LogAuthAttempt(claims.ServiceID, peerAddr, info.FullMethod, true, "stream authenticated")

		// Wrap the stream to inject claims into context
		wrappedStream := &authenticatedStream{
			ServerStream: ss,
			ctx:          context.WithValue(ctx, claimsKey, claims),
		}

		return handler(srv, wrappedStream)
	}
}

