// NewMeshService creates a new mesh service
func NewMeshService(validator *TokenValidator, auditLog *AuditLogger) *MeshService {
	return &MeshService{
		validator: validator,
		auditLog:  auditLog,
	}
}

// ProcessRequest handles an authenticated service mesh request
func (s *MeshService) ProcessRequest(ctx context.Context, req *ServiceRequest) (*ServiceResponse, error) {
	// Extract claims from context (set by interceptor)
	claims, ok := ctx.Value(claimsKey).(*TokenClaims)
	if !ok {
		return nil, status.Errorf(codes.Internal, "claims not found in context")
	}

	// Authorization: check if the service has the required permission
	requiredPerm := fmt.Sprintf("access:%s", req.ServiceName)
	hasPermission := false
	for _, perm := range claims.Permissions {
		if perm == requiredPerm || perm == "admin" {
			hasPermission = true
			break
		}
	}

	if !hasPermission {
		return nil, status.Errorf(codes.PermissionDenied,
			"service %s in namespace %s does not have permission %s",
			claims.ServiceID, claims.Namespace, requiredPerm)
	}

	log.Printf("Processing request from service=%s namespace=%s for target=%s",
		claims.ServiceID, claims.Namespace, req.ServiceName)

	return &ServiceResponse{
		Status:  "OK",
		Message: fmt.Sprintf("Request processed by %s for service %s", claims.ServiceID, req.ServiceName),
		Data:    []byte("response-data"),
	}, nil
}

// HealthCheck handles health check requests (still requires auth for mesh internal)
func (s *MeshService) HealthCheck(ctx context.Context) (*ServiceResponse, error) {
	claims, ok := ctx.Value(claimsKey).(*TokenClaims)
	if !ok {
		return nil, status.Errorf(codes.Internal, "claims not found in context")
	}

	return &ServiceResponse{
		Status:  "HEALTHY",
		Message: fmt.Sprintf("Health check from %s/%s", claims.Namespace, claims.ServiceID),
	}, nil
}

// --- TLS Configuration ---

// LoadTLSCredentials loads mTLS credentials for the server
func LoadTLSCredentials(certFile, keyFile, caFile string) (credentials.TransportCredentials, error) {
	// Load server certificate and key
	serverCert, err := tls.LoadX509KeyPair(certFile, keyFile)
	if err != nil {
		return nil, fmt.Errorf("failed to load server certificate: %w", err)
	}

	// Load CA certificate for client verification
	caCert, err := os.ReadFile(caFile)
	if err != nil {
		return nil, fmt.Errorf("failed to read CA certificate: %w", err)
	}

	certPool := x509.NewCertPool()
	if !certPool.AppendCertsFromPEM(caCert) {
		return nil, errors.New("failed to add CA certificate to pool")
	}

	tlsConfig := &tls.Config{
		Certificates: []tls.Certificate{serverCert},
		ClientAuth:   tls.RequireAndVerifyClientCert,
		ClientCAs:    certPool,
		MinVersion:   tls.VersionTLS13,
		CipherSuites: []uint16{
			tls.TLS_AES_256_GCM_SHA384,
			tls.TLS_AES_128_GCM_SHA256,
			tls.TLS_CHACHA20_POLY1305_SHA256,
		},
	}

	return credentials.NewTLS(tlsConfig), nil
}

