// --- Main ---

func main() {
	// Generate a shared secret for token signing (in production, use a secrets manager)
	sharedSecret := make([]byte, 32)
	if _, err := rand.Read(sharedSecret); err != nil {
		log.Fatalf("Failed to generate shared secret: %v", err)
	}

	// Initialize components
	validator := NewTokenValidator(sharedSecret)
	rateLimiter := NewRateLimiter(100, time.Minute) // 100 requests per minute per service
	auditLog := NewAuditLogger()

	// Register trusted services
	validator.RegisterService("api-gateway", []string{"access:user-service", "access:order-service", "admin"})
	validator.RegisterService("user-service", []string{"access:auth-service", "access:notification-service"})
	validator.RegisterService("order-service", []string{"access:inventory-service", "access:payment-service"})
	validator.RegisterService("monitoring", []string{"admin"})

	// Server options
	var serverOpts []grpc.ServerOption

	// Try to load TLS credentials; fall back to insecure for development
	certFile := os.Getenv("TLS_CERT_FILE")
	keyFile := os.Getenv("TLS_KEY_FILE")
	caFile := os.Getenv("TLS_CA_FILE")

	if certFile != "" && keyFile != "" && caFile != "" {
		tlsCreds, err := LoadTLSCredentials(certFile, keyFile, caFile)
		if err != nil {
			log.Fatalf("Failed to load TLS credentials: %v", err)
		}
		serverOpts = append(serverOpts, grpc.Creds(tlsCreds))
		log.Println("mTLS enabled")
	} else {
		log.Println("WARNING: Running without TLS - for development only!")
	}

	// Add interceptors
	serverOpts = append(serverOpts,
		grpc.UnaryInterceptor(AuthInterceptor(validator, rateLimiter, auditLog)),
		grpc.StreamInterceptor(StreamAuthInterceptor(validator, rateLimiter, auditLog)),
		grpc.MaxRecvMsgSize(4*1024*1024),    // 4MB max message size
		grpc.MaxSendMsgSize(4*1024*1024),
		grpc.MaxConcurrentStreams(100),
	)

	// Create gRPC server
	grpcServer := grpc.NewServer(serverOpts...)

	// Create and register service
	meshService := NewMeshService(validator, auditLog)
	RegisterMeshServiceServer(grpcServer, meshService)

	// Start listening
	listenAddr := os.Getenv("LISTEN_ADDR")
	if listenAddr == "" {
		listenAddr = ":50051"
	}

	listener, err := net.Listen("tcp", listenAddr)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", listenAddr, err)
	}

	log.Printf("Service mesh gRPC server starting on %s", listenAddr)

	// Demo: Generate a sample token for testing
	demoToken, err := validator.GenerateToken("api-gateway", "production", []string{"access:user-service", "admin"}, 1*time.Hour)
	if err != nil {
		log.Fatalf("Failed to generate demo token: %v", err)
	}
	log.Printf("Demo token for api-gateway: %s", demoToken)

	// Demonstrate token validation
	claims, err := validator.ValidateToken(demoToken)
	if err != nil {
		log.Fatalf("Demo token validation failed: %v", err)
	}
	log.Printf("Demo token validated: service=%s namespace=%s permissions=%v expires=%v",
		claims.ServiceID, claims.Namespace, claims.Permissions, claims.ExpiresAt)

	// Start serving
	if err := grpcServer.Serve(listener); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}